const affiliate = $input.first()?.json;
if (!affiliate) return [];
const amount = Number('{{$json.body.amount}}');
const rate = 0.40; // TODO: fetch from aff_commission_settings
const commission = amount * rate;
return [{ json: { affiliate_id: affiliate.affiliate_id, source: 'subscription', source_id: '{{$json.body.payment_id}}', referred_user_id: '{{$json.body.user_id}}', gross_amount: amount, commission_rate: rate, commission_amount: commission, claimable_at: new Date(Date.now() + 14*24*60*60*1000).toISOString() } }];
